| text       = <div style="text-align: center;">This [[Help:Category|category]] contains {{#ifeq:{{{container}}}|yes||{{#switch:{{{contents}}}
 | articles   = articles
 | audio      = audio files
 | categories = categories
 | images     = images
 | portals    = portals
 | redirects  = redirects
 | stubs      = stubs
 | templates  = templates
 | users      = users
 | pages
 }} {{#ifeq:{{{subcategories}}}|no||and}}}} {{#ifeq:{{{subcategories}}}|no||[[Wikipedia:Categorization#Subcategorization|subcategories]] {{#ifeq:{{{class}}}|admin|of {{#switch:{{{contents}}}
 | articles   = articles
 | audio      = audio files
 | categories = categories
 | images     = images
 | portals    = portals
 | redirects  = redirects
 | stubs      = stubs
 | templates  = templates
 | users      = users
 | pages
 }}}}}} {{#ifeq:{{{type}}}|tracking|tagged with {{tlx|{{{template}}}|{{#if:{{{parameter|}}}|{{{parameter}}}}}}}{{#ifeq:{{{variant}}}|yes|&#32;or a variant thereof}}|belonging to the {{#switch:{{{type}}}
 | double|set    = set
 | set-and-topic = set and topic
 | topic
 }} '''''{{#if:{{{first|}}}|{{{first}}}|{{#if:{{{name|}}}|[[{{{name}}}]]|[[{{PAGENAME}}]]}}}}'''''{{#ifeq:{{{contents}}}|categories||{{#ifeq:{{{contents}}}|container||{{#ifeq:{{{contents}}}|lists||{{#ifeq:{{{lists}}}|no||{{#ifeq:{{{type}}}|double|, as well as lists of {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}|{{#ifeq:{{{type}}}|set|, as well as lists of {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}|{{#ifeq:{{{type}}}|set-and-topic|, as well as lists of {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}}}}}}}}}}}}}}}}}. {{#ifeq:{{{type}}}|double|{{#if:{{{topic|}}}|For topics related to {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}, see [[:Category:{{{topic}}}]].}}|{{#ifeq:{{{type}}}|set|{{#if:{{{topic|}}}|For topics related to {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}, see [[:Category:{{{topic}}}]].}}}}}}</div>

{{#switch:{{{class}}}
| admin    = {{Show|[[File:Wikipedia-logo.svg|20px]] [[Wikipedia:Categorization#Wikipedia administrative categories|Administrative category]]|This category is part of the administration of Wikipedia and is not part of the encyclopaedia. It contains pages that are not [[Wikipedia:What is an article?|articles]] or it groups articles by status rather than content.}}
| content  = {{Show|[[File:Wiki puzzle.svg|20px]] [[Wikipedia:Categorization#Content category|Content category]]|This category is part of the encyclopaedia. It should only contain articles and/or subcategories. Related administration pages should be linked, not included in the category.}}
| contents = {{Show|[[File:Wikipedia svg logo-en.svg|20px]] [[Wikipedia:Categorization#Contents category|Contents category]]|This category is a Wikipedia contents page. It is {{#ifeq:{{FULLPAGENAME}}|Category:Contents|the highest-level category|one of the highest-level categories}}.}}
| {{Error|This category is unclassified!}}
}}

{{#switch:{{{type}}}
| double        = {{Show|[[File:Double-arrow.svg|20px]] [[Wikipedia:Categorization#Double category|Double category]]|This category contains a [[Wikipedia:Categorization#Set category|set]] of articles and their corresponding [[Wikipedia:Categorization#Topic category|topic categories]]. It should only contain individual {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}} and lists of {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}. Topics related to the set should be placed in relevant [[Wikipedia:Categorization#Topic category|topic categories]]{{#if:{{{topic|}}}|, such as [[:Category:{{{topic}}}]]}}. {{#if:{{{individual|}}}|Topics related to an individual {{{individual}}} should be placed in the respective topic category.}}}}{{Category other|[[Category:Double categories]]}}
| intermediate  = {{Show|[[File:Venn0001.svg|20px]] [[Wikipedia:Categorization#Intermediate category|Intermediate category]]|This category serves as a cross-over point between two category trees. It should only contain categories.}}
| set           = {{Show|[[File:Easter-Eggs no background.gif|20px]] [[Wikipedia:Categorization#Set category|Set category]]|This category contains a set of pages in a particular group. It should only contain individual {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}, as well as subcategories and lists of {{#if:{{{name|}}}|{{{name}}}|{{PAGENAME}}}}. Topics related to the set {{#if:{{{individual|}}}|or an individual {{{individual}}}}} should be placed in relevant [[Wikipedia:Categorization#Topic category|topic categories]]{{#if:{{{topic|}}}|, such as [[:Category:{{{topic}}}]]}}.}}{{Category other|[[Category:Set categories]]}}
| set-and-topic = {{Show|[[File:Easter-Eggs no background.gif|20px]] [[Wikipedia:Categorization#Set-and-topic category|Set-and-topic category]] [[File:Big Book blue.svg|20px]]|This category contains a [[Wikipedia:Categorization#Set category|set]] of pages in a particular group, as well as [[Wikipedia:Categorization#Topic category|topics]] related to the set.}}{{Category other|[[Category:Set categories]]}}
| topic         = {{Show|[[File:Big Book blue.svg|20px]] [[Wikipedia:Categorization#Topic category|Topic category]]|This category contains pages related to a particular topic.}}
| tracking      = {{Show|[[File:Magnifying glass 01.svg|20px]] Tracking category|This category maintains a [[Wikipedia:Categorization#Set category|set]] of pages tagged with a particular template. Pages are automatically added to the category or one of its subcategories. {{#ifeq:{{{hidden}}}|no|The category is not [[Wikipedia:Categorization#Hidden category|hidden]] on its member pages.|The category is [[Wikipedia:Categorization#Hidden category|hidden]] on its member pages, unless the appropriate [[Special:Preferences|user preference]] is set. __HIDDENCAT__}}}}{{Category other|[[Category:Tracking categories]]}}
| universal     = {{Show|[[File:Globe.svg|20px]] [[Wikipedia:Categorization#Universal category|Universal category]]|This tracking category maintains a complete [[Wikipedia:Categorization#Set category|set]] of all pages within the related category tree. Pages are added to the category automatically. The category is [[Wikipedia:Categorization#Hidden category|hidden]] on its member pages, unless the appropriate [[Special:Preferences|user preference]] is set.}} __HIDDENCAT__
| {{Error|This category does not have a type!}}
}}

