 | stubs          = {{Show|[[File:Stub W.svg|20px]] [[Wikipedia:Categorization#Stub category|Stub category]]|This is a category of [[Wikipedia:Stub|stubs]].}}
 | templates      = {{Show|[[File:Curly Brackets.svg|20px]] [[Wikipedia:Categorization#Template category|Template category]]|This is a category of [[Help:Template|templates]].}}
 | users          = {{Show|[[File:User.svg|20px]] [[Wikipedia:Categorization#User page category|User page category]]|This is a category of [[Wikipedia:Wikipedians|Wikipedia users]].}}
 | variety        = {{Show|[[File:Psychedelic dingbats.png|20px]] [[Wikipedia:Categorization#Variety category|Variety category]]|This category contains a variety of different kinds of pages.}}
